<body>

    <header>
        <h1>WASTETOKEN MINT</h1>
        <p style="font-size: 1.5em; color: #aaa;">Forging the Future of Digital Collectibles into Tangible Metal.</p>
    </header>

    <!-- HERO SECTION -->
    <section id="hero-container">
